    var weatherUtils = require('./utils/weatherUtils'),
        clubLogger = require(settings.path.root('clubLogger')),
        clubSettings = settings.club;

    server.get('/api/weather/:location', function(req, res, next) {
        async.waterfall([
            function fetchWeather(callback) {
                weatherUtils.getCurrentWeather(req.params.location, callback);
            },
            function formatResponse(weatherData, callback) {
                var formatted = _.mapKeys(weatherData, function(value, key) {
                    return key.toLowerCase();
                });
                callback(null, formatted);
            }
        ], function(err, result) {
            if (err) return next(err);
            res.send(result);
            clubLogger.info('Weather data served for ' + req.params.location);
        });

